#ifdef __cplusplus
extern "C"
{
#endif

#include "platform.h"
#include "syscall.h"

#include <stdint.h>
#include <stdio.h>

#define CAUSE_MACHINE_ECALL 0xb
#define SYSCALL_TABLE_SIZE 2012

#define PRINT_ERROR(format, ...) \
  printf("\033[31m[ERROR] " format "\033[0m", ##__VA_ARGS__)

#define WRITE_ERROR(format, ...) do { \
  char buf[100]; \
  int len = sprintf(buf, "\033[31m[ERROR] " format "\033[0m\n", ##__VA_ARGS__); \
  _write(2, buf, len); \
} while(0)


typedef long (*syscall_t)(long, long, long, long, long, long, long);
static void* syscall_table[SYSCALL_TABLE_SIZE];

static void init_syscall_table()
{
  syscall_table[SYS_open] = (void*) _open;
  syscall_table[SYS_write] = (void*) _write;
  syscall_table[SYS_getcwd] = (void*) _getcwd;
  syscall_table[SYS_lseek] = (void*) _lseek;
  syscall_table[SYS_read] = (void*) _read;
  syscall_table[SYS_close] = (void*) _close;
  syscall_table[SYS_gettimeofday] = (void*) _gettimeofday;
  syscall_table[SYS_access] = (void*) _access;
  syscall_table[SYS_faccessat] = (void*) _faccessat;
  syscall_table[SYS_fstat] = (void*) _fstat;
  syscall_table[SYS_fstatat] = (void*) _fstatat;
  syscall_table[SYS_link] = (void*) _link;
  syscall_table[SYS_lstat] = (void*) _lstat;
  syscall_table[SYS_stat] = (void*) _stat;
  syscall_table[SYS_openat] = (void*) _openat;
  syscall_table[SYS_rename] = (void*) _rename;
  syscall_table[SYS_unlink] = (void*) _unlink;
}

__attribute__((used, noreturn)) void _exit(int exit_status);

long do_syscall(
  long a0, long a1, long a2, long a3, long a4, long a5, unsigned long n)
{

  syscall_t f = (syscall_t) syscall_table[n];
  return f(a0, a1, a2, a3, a4, a5, n);
}

// Exception Handler
void exception_handler(void)
{
  uint32_t mcause, mdcause, mepc, mtval;

  asm volatile("csrr %0, mcause" : "=r"(mcause));
  asm volatile("csrr %0, mdcause" : "=r"(mdcause));
  asm volatile("csrr %0, mepc" : "=r"(mepc));
  asm volatile("csrr %0, mtval" : "=r"(mtval));

  WRITE_ERROR("Trap occurred!");
  WRITE_ERROR("mcause: 0x%x", mcause);
  WRITE_ERROR("mdcause: 0x%x", mdcause);
  WRITE_ERROR("mepc: 0x%x", mepc);
  WRITE_ERROR("mtval: 0x%x", mtval);

  if ((mcause & 0x80000000) == 0) {
    WRITE_ERROR("Exception code: %d", mcause);
  } else {
    WRITE_ERROR("Interrupt occurred! Cause: %d", mcause & 0x7FFFFFFF);
  }

  asm volatile("csrw mepc, %0" : : "r"(mepc + 4));
  _exit(mcause); // TODO: what should we assign here?
  asm volatile("mret");
}

static void handle_syscall(SAVED_CONTEXT* tf)
{
#ifndef __riscv_32e

  tf->x10 =
    do_syscall(tf->x10, tf->x11, tf->x12, tf->x13, tf->x14, tf->x15, tf->x17);
#else
  tf->x10 =
    do_syscall(tf->x10, tf->x11, tf->x12, tf->x13, tf->x14, tf->x15, tf->x5);
#endif
  tf->mepc += 4;
}

void handle_trap(unsigned long cause, SAVED_CONTEXT* tf)
{
  typedef void (*trap_handler)(SAVED_CONTEXT*);
  trap_handler f;

  if (cause != CAUSE_MACHINE_ECALL) {
    f = (trap_handler) exception_handler;
  } else {
    f = handle_syscall;
  }

  f(tf);
}

extern void m_trap_entry();

__attribute__((constructor)) void init_mtvec(void)
{
  init_syscall_table();
  uintptr_t handler_address = (uintptr_t) &m_trap_entry;
  asm volatile("csrw mtvec, %0" : : "r"(handler_address));
}

#ifdef __cplusplus
}
#endif

