#pragma once

#include "custom_master.hpp"
#include "htif/command.hpp"
#include "htif/picolib.hpp"
#include "memory_region.hpp"
#include "pybind11.hpp"
#include "simple_memory.hpp"

#include <fcntl.h>
#include <spdlog/spdlog.h>
#include <systemc>
#include <tlm>
#include <tlm_utils/simple_target_socket.h>
#include <unistd.h>

#include <cstdint>

#include <span>

static constexpr uint64_t HTIF_PUTCHAR_OFFSET = 0x4;
static constexpr uint64_t HTIF_CMD_OFFSET = 0x10;
static constexpr uint64_t HTIF_CMD_HIGH_OFFSET = 0x14;
static constexpr uint64_t INT_TRIGGER_OFFSET = 0x20;

extern sc_core::sc_semaphore custom_master_sem;
extern SubPortTest subport_test;

enum class SimCommand : uint32_t
{
  FINISHED = 0x01234567,
  PASSED = 0x01234568,
  FAILED = 0x01234569,
  WARNING = 0x01234570,
  SKIPPED = 0x01234571,
  NEWLINE = 0xddddeeee,
  // below are for tests only
  TEST_ILM = 0x00abcde0,
  TEST_DLM = 0x00abcde1,
  TEST_HVM = 0x00abcde2,
};

constexpr size_t SYSCALL_TABLE_SIZE = 100;
constexpr size_t MAGIC_MEM_SIZE = 8;
constexpr int HTIF_32BIT_PARTS = 2;

template<std::size_t BusWidth = 32>
class SimControl : public sc_core::sc_module
{
public:
  using sys_func_ptr = uint64_t (SimControl::*)(
    uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t);

  tlm_utils::simple_target_socket<SimControl, BusWidth> socket{"tsck"};
  int32_t exits;
  const MemoryRegion region;

  SimControl(const sc_core::sc_module_name& name,
             const MemoryRegion& region,
             SimpleMemory<BusWidth>& main_memory,
             sc_core::sc_signal<sc_dt::sc_uint<31>>& int_trigger,
             const sc_core::sc_clock& clk)
      : sc_core::sc_module{name},
        exits(-1),
        region(region),
        data_region(main_memory),
        int_trigger(int_trigger),
        clk(clk),
        riscv_xlen(0),
        partial_htif_command(0),
        htif_parts_received(0)
  {
    sim_syscall_table[5] = &SimControl::handle_gettimeofday;
    sim_syscall_table[6] = &SimControl::handle_open;
    sim_syscall_table[7] = &SimControl::handle_write;
    sim_syscall_table[8] = &SimControl::handle_getcwd;
    sim_syscall_table[9] = &SimControl::handle_lseek;
    sim_syscall_table[10] = &SimControl::handle_read;
    sim_syscall_table[11] = &SimControl::handle_flen;
    sim_syscall_table[12] = &SimControl::handle_close;
    sim_syscall_table[13] = &SimControl::handle_access;
    sim_syscall_table[14] = &SimControl::handle_faccessat;
    sim_syscall_table[15] = &SimControl::handle_fstat;
    sim_syscall_table[16] = &SimControl::handle_fstatat;
    sim_syscall_table[17] = &SimControl::handle_link;
    sim_syscall_table[18] = &SimControl::handle_lstat;
    sim_syscall_table[19] = &SimControl::handle_stat;
    sim_syscall_table[20] = &SimControl::handle_openat;
    sim_syscall_table[21] = &SimControl::handle_rename;
    sim_syscall_table[22] = &SimControl::handle_unlink;

    this->socket.register_b_transport(this, &SimControl::b_transport);
  }

  void b_transport(tlm::tlm_generic_payload& trans, sc_core::sc_time& /*delay*/)
  {
    handle_trans(trans);
    trans.set_response_status(tlm::TLM_OK_RESPONSE);
  }

#if ENABLE_PYBIND11
  static void bind_pybind11(pybind11::module_& m)
  {
    char namebuf[30];
    snprintf(namebuf, sizeof(namebuf), "sim_control_%zu", BusWidth);
    pybind11::class_<SimControl>(m, namebuf)
      .def_readwrite("exits", &SimControl::exits);
  }
#endif

#include "htif/sys_call.hpp"

private:
  SimpleMemory<BusWidth>& data_region;
  sc_core::sc_signal<sc_dt::sc_uint<31>>& int_trigger;
  const sc_core::sc_clock& clk;
  sys_func_ptr sim_syscall_table[SYSCALL_TABLE_SIZE] = {};
  uint32_t riscv_xlen;
  uint64_t partial_htif_command;
  int htif_parts_received;

  void handle_trans(tlm::tlm_generic_payload& trans)
  {
    const auto addr = trans.get_address();
    const auto len = trans.get_data_length();
    const auto buf = std::span{trans.get_data_ptr(), len};
    const auto offset = addr - region.base_address;

    if (trans.is_read()) {
      spdlog::debug("sim_control: read, addr={:#x}, len={}", addr, len);
      return;
    }

    spdlog::debug("sim_control: write, addr={:#x}, len={}", addr, len);

    if (offset == 0 && len == 4) {
      handle_sim_command(unpack<uint32_t>(buf));
    } else if (offset == HTIF_PUTCHAR_OFFSET && len == 1) {
      std::putchar(buf[0]);
    } else if (offset == HTIF_CMD_OFFSET) {
      (len == 8) ? handle_htif_64bit_write(buf)
                 : handle_htif_32bit_low_write(buf);
    } else if (offset == HTIF_CMD_HIGH_OFFSET && len == 4) {
      handle_htif_32bit_high_write(buf);
    } else if (offset == INT_TRIGGER_OFFSET && len == 4) {
      auto val = unpack<uint32_t>(buf);
      spdlog::debug("sim_control: int_trigger = {:#x}", val);
      int_trigger.write(val);
      // clear the IRQ after one cycle
      if (val != 0) {
        wait(clk.posedge_event());
        int_trigger.write(0);
      }
    } else {
      spdlog::warn("sim_control: spurious write at {:#x}, length {}", addr,
                   len);
    }
  }

  void handle_sim_command(uint32_t command)
  {
    spdlog::info("sim_control: received command {:#x}", command);
    switch (static_cast<SimCommand>(command)) {
    case SimCommand::NEWLINE:
      std::putchar('\n');
      break;
    case SimCommand::TEST_ILM:
      subport_test = SubPortTest::TEST_ILM;
      custom_master_sem.post();
      break;
    case SimCommand::TEST_DLM:
      subport_test = SubPortTest::TEST_DLM;
      custom_master_sem.post();
      break;
    case SimCommand::TEST_HVM:
      subport_test = SubPortTest::TEST_HVM;
      custom_master_sem.post();
      break;
    case SimCommand::PASSED:
    case SimCommand::FINISHED:
      spdlog::info("sim_control: Test PASSED");
      exits = 0;
      break;
    case SimCommand::SKIPPED:
      spdlog::info("sim_control: Test SKIPPED");
      exits = 0;
      break;
    case SimCommand::FAILED:
      spdlog::info("sim_control: Test FAILED");
      exits = 1;
      break;
    case SimCommand::WARNING:
      spdlog::warn("sim_control: Test WARNING");
      exits = 1;
      break;
    default:
      if (command < 256)
        exits = command;
      else
        spdlog::warn("sim_control: unknown command {:#x}", command);
      break;
    }
  }

  template<typename T>
  static T unpack(const std::span<uint8_t>& buf)
  {
    T result = 0;
    for (size_t i = 0; i < sizeof(T); ++i)
      result |= static_cast<T>(buf[i]) << (i * 8);
    return result;
  }

  void execute_htif_syscall()
  {
    command_t cmd(partial_htif_command);
    if (cmd.device() != 0 || cmd.cmd() != 0) {
      spdlog::warn("sim_control: unknown device: #{}", cmd.device());
      return;
    }
    dispatch(cmd);
    partial_htif_command = 0;
    htif_parts_received = 0;
  }

  void handle_htif_64bit_write(const std::span<uint8_t>& buf)
  {
    command_t cmd(unpack<uint64_t>(buf));
    if (cmd.device() == 0 && cmd.cmd() == 0)
      dispatch(cmd);
    else
      spdlog::warn("sim_control: unknown device: #{}", cmd.device());
  }

  void handle_htif_32bit_low_write(const std::span<uint8_t>& buf)
  {
    partial_htif_command |= unpack<uint32_t>(buf);
    if (++htif_parts_received == HTIF_32BIT_PARTS)
      execute_htif_syscall();
  }

  void handle_htif_32bit_high_write(const std::span<uint8_t>& buf)
  {
    partial_htif_command |= static_cast<uint64_t>(unpack<uint32_t>(buf)) << 32;
    if (++htif_parts_received == HTIF_32BIT_PARTS)
      execute_htif_syscall();
  }

  void dispatch(command_t cmd)
  {
    uint64_t syscall_args[MAGIC_MEM_SIZE];
    auto addr_offset = cmd.payload() - data_region.region.base_address;
    auto src = data_region.data.begin() + addr_offset;

    std::copy(src, src + sizeof(syscall_args),
              reinterpret_cast<uint8_t*>(syscall_args));

    spdlog::debug("sim_control: args: {:#x}, {:#x}, {:#x}, "
                  "{:#x}, {:#x}, {:#x}, {:#x}",
                  syscall_args[0], syscall_args[1], syscall_args[2],
                  syscall_args[3], syscall_args[4], syscall_args[5],
                  syscall_args[6]);

    auto syscall_num = syscall_args[0];
    if (syscall_num >= SYSCALL_TABLE_SIZE || !sim_syscall_table[syscall_num]) {
      spdlog::critical("sim_control: invalid syscall number {}", syscall_num);
      syscall_args[0] = static_cast<uint64_t>(-1);
    } else {
      syscall_args[0] = (this->*sim_syscall_table[syscall_num])(
        syscall_args[1], syscall_args[2], syscall_args[3], syscall_args[4],
        syscall_args[5], syscall_args[6], syscall_args[7]);
    }

    std::copy(reinterpret_cast<uint8_t*>(syscall_args),
              reinterpret_cast<uint8_t*>(syscall_args) + sizeof(syscall_args),
              src);
  }
};

